1	const PROCESSING_FEE = 5;
2	const BLOCK_OF_THREE_SIZE = 3;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const CURSED_SURCHARGE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
6	const HIGH_ENCHANTMENT_THRESHOLD = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
20	type Step = { op: "quote"; items: Item[] };
21	type Scenario = { customer: unknown; steps: Step[] };
22	
23	const basePremiumFor = (type: string): number => BASE_PREMIUM[type] ?? 0;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const isMainItem = (item: Item): boolean => !isComponent(item);
28	
29	const groupByType = (items: Item[]): Map<string, number> =>
30	  items.reduce((counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1), new Map<string, number>());
31	
32	const componentGroupPremium = (type: string, count: number): number =>
33	  count === BLOCK_OF_THREE_SIZE ? BLOCK_OF_THREE_PREMIUM : count * basePremiumFor(type);
34	
35	const componentsPremium = (items: Item[]): number =>
36	  Array.from(groupByType(items.filter(isComponent)))
37	    .reduce((sum, [type, count]) => sum + componentGroupPremium(type, count), 0);
38	
39	const isHighlyEnchanted = (item: Item): boolean =>
40	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
41	
42	const itemSurcharge = (item: Item): number =>
43	  (item.cursed ? CURSED_SURCHARGE : 0) +
44	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
45	
46	const itemPremium = (item: Item): number =>
47	  basePremiumFor(item.type) * (1 + itemSurcharge(item));
48	
49	const mainItemsPremium = (items: Item[]): number =>
50	  items.filter(isMainItem)
51	    .reduce((sum, item) => sum + itemPremium(item), 0);
52	
53	const itemsPremium = (items: Item[]): number =>
54	  mainItemsPremium(items) + componentsPremium(items);
55	
56	const quote = ({ items }: Step): { premium: number } => ({
57	  premium: itemsPremium(items) + PROCESSING_FEE,
58	});
59	
60	export const runScenario = (input: unknown): unknown => {
61	  const { steps } = input as Scenario;
62	  return { results: steps.map(quote) };
63	};
